var e=JSON.parse(`[{"id":"L2_1","type":"subtitle","speaker":null,"text":{"KOREA":"1888년 9월 30일 런던, <color=#ffd34c>황금 새벽회</color> 지하 사원\\n<color=#ffd34c>심야</color>","JPN":"1888年9月30日　ロンドン、<color=#ffd34c>黄金の暁団</color>地下寺院\\n<color=#ffd34c>深夜</color>","ENG":"September 30, 1888, London, <color=#ffd34c>Golden Dawn</color> Underground Temple,\\n<color=#ffd34c>Midnight</color>","TWN":"1888年9月30日 倫敦, <color=#ffd34c>黃金黎明會</color> 地下寺廟\\n<color=#ffd34c>深夜</color>"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L6_1","type":"dialog","speaker":"SISTER_PRYDWEN_NPC_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"UNDER","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SISTER_PRYDWEN_NPC_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L7_1","type":"dialog","speaker":"SISTER_PRYDWEN_NPC_NULL","text":{"KOREA":"좋아, 지금이라면 괜찮겠지.","JPN":"よし、今なら大丈夫でしょう。","ENG":"Okay, it should be okay now.","TWN":"很好，這樣就差不多了吧。"},"stage":{"bg":"UNDER","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SISTER_PRYDWEN_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"SWAN_SWANSONG_NPC_NULL","text":{"KOREA":"단지 교단에 입회하는 것만으로 그 비싼 마석을 아무렇지도 않게 넘기다니…….","JPN":"教団に入会しただけで、高額な魔石を渡してくれるなんて……","ENG":"I can't believe they're giving away those expensive Mana Stones for just joining the order...","TWN":"僅僅是加入教團，就能毫不費力地獲得昂貴的魔石……"},"stage":{"bg":"UNDER","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWAN_SWANSONG_NPC_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"SWAN_SWANSONG_NPC_NULL","text":{"KOREA":"황금 새벽회가 어떻게 마석을 만들어내는지는 모르겠지만.","JPN":"黄金の暁団がどうやって魔石を作っているのかはわからないけど。","ENG":"I'm not sure how the Golden Dawn is able to create Mana Stones, but.","TWN":"雖然不知道黃金黎明會是怎麼製造的。"},"stage":{"bg":"UNDER","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWAN_SWANSONG_NPC_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"SWAN_SWANSONG_NPC_NULL","text":{"KOREA":"이런 식이라면 마석이 필요한 이능력자를 잔뜩 끌어들일 수 있었을 거야.","JPN":"このやり方なら、魔石を求めている異能力者をたくさん入会させられるはず。","ENG":"They should be able to attract the Supernaturals as they need the Mana Stones.","TWN":"照這樣下去，肯定能吸引一大批需要魔石的超能力者。"},"stage":{"bg":"UNDER","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWAN_SWANSONG_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"SWAN_SWANSONG_NPC_NULL","text":{"KOREA":"문제는 이곳의 신도 명단을 어떻게 얻어내느냐인데…….","JPN":"問題は、ここの信徒のリストをどうやって手に入れるかだけど……","ENG":"The issue at hand now is how I'm going to obtain the list of their members...","TWN":"問題是如何獲取名單……"},"stage":{"bg":"UNDER","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWAN_SWANSONG_NPC_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"SWAN_SWANSONG_NPC_NULL","text":{"KOREA":"……잠깐.","JPN":"……待って。","ENG":"...Hold on.","TWN":"……等等。"},"stage":{"bg":"UNDER","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWAN_SWANSONG_NPC_NULL","face":"UNIT_SURPRISE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L17_1","type":"dialog","speaker":"SWAN_SWANSONG_NPC_NULL","text":{"KOREA":"내가 뭘 이렇게까지 진지하게 생각하고 있는 거야?","JPN":"私、なんでこんなに真剣になっているの？","ENG":"Why am I thinking about this so seriously?","TWN":"我想這麼認真幹什麼呢？"},"stage":{"bg":"UNDER","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWAN_SWANSONG_NPC_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"SWAN_SWANSONG_NPC_NULL","text":{"KOREA":"이건 그 남자의 일이잖아? 심야의 살인마 따위 내가 알게 뭐람?","JPN":"これはあの男の仕事よ？　深夜の殺人鬼なんか私の知ったことじゃない。","ENG":"This is his job, not mine. Why should I care about the Midnight Killer?","TWN":"這不是那個男人的事嗎？什麼午夜殺人魔，我才不管呢？"},"stage":{"bg":"UNDER","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWAN_SWANSONG_NPC_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"SWAN_SWANSONG_NPC_NULL","text":{"KOREA":"어차피 나는…….","JPN":"どうせ私は……","ENG":"Because I'm...","TWN":"反正我……"},"stage":{"bg":"UNDER","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWAN_SWANSONG_NPC_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"ABBERLINE_SWANSONG_NPC_NULL","text":{"KOREA":"그렇다네. 비록 멀리서 바라볼 뿐이지만 항상 응원하고 있어.","JPN":"そのとおりだ。ただ遠くから見守っているだけだが、いつも応援している。","ENG":"Although I saw from afar, I'll always be cheering for you.","TWN":"是的。雖然只能遠遠地看著，但我一直在為你加油。"},"stage":{"bg":"BACKSTREET3","bgm":"CUTSCENE_TALK_06","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"ABBERLINE_SWANSONG_NPC_NULL","face":"UNIT_LAUGH"},"R":null}},"sfx":"FX_COMBAT_ALL_MAGIC_SPELL_LIGHT_02"},{"id":"L23_1","type":"dialog","speaker":"ABBERLINE_SWANSONG_NPC_NULL","text":{"KOREA":"팬이니까 말이야, 자네의.","JPN":"ファンだからな、君の。","ENG":"I'm actually a fan of yours.","TWN":"史旺，我是你的粉絲。"},"stage":{"bg":"BACKSTREET3","bgm":"CUTSCENE_TALK_06","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"ABBERLINE_SWANSONG_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"ABBERLINE_SWANSONG_NPC_NULL","text":{"KOREA":"무엇보다도 말이지.","JPN":"なにより。","ENG":"Above all else.","TWN":"最重要的是。"},"stage":{"bg":"LONDON_VICTORIA","bgm":"CUTSCENE_TALK_06","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"ABBERLINE_SWANSONG_NPC_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_COMBAT_ALL_MAGIC_SPELL_LIGHT_02"},{"id":"L25_1","type":"dialog","speaker":"ABBERLINE_SWANSONG_NPC_NULL","text":{"KOREA":"자네와 내가 이렇게 만나게 된 것 자체가 그 훌륭한 반증이지 않은가?","JPN":"君と私がこうして出会えたこと自体、立派な反証ではないだろうか。","ENG":"Isn't the fact that you and I met like this an excellent rebuttal?","TWN":"你和我能這樣相遇，本身就是最好的證明，不是嗎？"},"stage":{"bg":"LONDON_VICTORIA","bgm":"CUTSCENE_TALK_06","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"ABBERLINE_SWANSONG_NPC_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L26_1","type":"dialog","speaker":"ABBERLINE_SWANSONG_NPC_NULL","text":{"KOREA":"후후, 정답이야.","JPN":"ふふ、正解だ。","ENG":"Haha. That's correct.","TWN":"哈哈，答對了。"},"stage":{"bg":"BACKSTREET3","bgm":"CUTSCENE_TALK_06","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"ABBERLINE_SWANSONG_NPC_NULL","face":"UNIT_LAUGH"},"R":null}},"sfx":"FX_COMBAT_ALL_MAGIC_SPELL_LIGHT_02"},{"id":"L27_1","type":"dialog","speaker":"ABBERLINE_SWANSONG_NPC_NULL","text":{"KOREA":"역시 자네는 소질이 있군. 내 눈은 틀리지 않았어.","JPN":"やはり君には素質がある。私の目に狂いはなかったようだ。","ENG":"I knew you showed potential. My eyes are never wrong.","TWN":"果然你很有天賦。我的眼光沒有錯。"},"stage":{"bg":"BACKSTREET3","bgm":"CUTSCENE_TALK_06","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"ABBERLINE_SWANSONG_NPC_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L31_1","type":"dialog","speaker":"SWAN_SWANSONG_NPC_NULL","text":{"KOREA":"으으! 무슨 엉뚱한 생각을 하고 있는 거야!","JPN":"うう…！　何考えてるの私！","ENG":"Errgh! Why am I thinking about him?","TWN":"呃呃！你在瞎想什麼呢！"},"stage":{"bg":"BACKSTREET","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWAN_SWANSONG_NPC_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L32_1","type":"dialog","speaker":"SWAN_SWANSONG_NPC_NULL","text":{"KOREA":"정신차려, 스완! 어차피 그 능구렁이 같은 남자, 사진만 돌려받으면 볼 일도 없잖아?","JPN":"しっかりするのよ、スワン！　あの古狸みたいな男、写真さえ返してもらえたら用はない！","ENG":"Get a hold of yourself, Swan! You won't see that sly man ever again if you get that photo back, right?","TWN":"清醒點，史旺！只要把照片拿回來，就不用再見到那個狡猾的男人了，不是嗎？"},"stage":{"bg":"BACKSTREET","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWAN_SWANSONG_NPC_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L33_1","type":"dialog","speaker":"SWAN_SWANSONG_NPC_NULL","text":{"KOREA":"그래, 내가 알아낸 걸 말하고, 사진을 돌려달라고 하자.","JPN":"そう、私が手に入れた情報を渡して、写真を返してもらおう。","ENG":"Okay. I'll tell him what I found out and get it back.","TWN":"好吧，這就回去告訴他我的發現，然後讓他把照片還給我。"},"stage":{"bg":"BACKSTREET","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWAN_SWANSONG_NPC_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L34_1","type":"dialog","speaker":"SWAN_SWANSONG_NPC_NULL","text":{"KOREA":"이 정도 했으면, 사진 값은…….","JPN":"ここまでやったら写真の代価としては十分……","ENG":"I think I've done enough to get the photo back...","TWN":"做到這種程度，應該也抵得上那張照片的價值了……"},"stage":{"bg":"BACKSTREET","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWAN_SWANSONG_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L37_1","type":"dialog","speaker":"SWAN_SWANSONG_NPC_NULL","text":{"KOREA":"그나저나 여긴 어디지?","JPN":"というか、ここはどこ？","ENG":"Where am I?","TWN":"話說這裡是哪裡？"},"stage":{"bg":"BACKSTREET","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWAN_SWANSONG_NPC_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L38_1","type":"dialog","speaker":"SWAN_SWANSONG_NPC_NULL","text":{"KOREA":"안개가 너무 짙어서 방향을 잃어버리고 말았어.","JPN":"霧が濃すぎて、方向がわからなくなってしまった。","ENG":"The fog is too dense that I lost my sense of direction.","TWN":"霧太濃了，不知不覺迷失了方向。"},"stage":{"bg":"BACKSTREET","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWAN_SWANSONG_NPC_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L39_1","type":"dialog","speaker":"SWAN_SWANSONG_NPC_NULL","text":{"KOREA":"음?","JPN":"うん？","ENG":"Hmm?","TWN":"嗯？"},"stage":{"bg":"BACKSTREET","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWAN_SWANSONG_NPC_NULL","face":"UNIT_SURPRISE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L42_1","type":"dialog","speaker":"SWAN_SWANSONG_NPC_NULL","text":{"KOREA":"뭔가가……? 방금 기분 나쁜 뭔가 물컹하고 밟혔는데……?","JPN":"何かが……？　今、何か足にぐにゃっとしたものが……？","ENG":"A squish...? I think I stepped on something that feels squishy...","TWN":"什麼東西……？剛剛踩到什麼黏糊糊的東西，感覺很不舒服……？"},"stage":{"bg":"BACKSTREET","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWAN_SWANSONG_NPC_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L43_1","type":"dialog","speaker":"SWAN_SWANSONG_NPC_NULL","text":{"KOREA":"설마……?","JPN":"まさか……？","ENG":"Is it...?","TWN":"不會吧……？"},"stage":{"bg":"BACKSTREET","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWAN_SWANSONG_NPC_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L47_1","type":"dialog","speaker":"SWAN_SWANSONG_NPC_NULL","text":{"KOREA":"이, 이건……?","JPN":"こ、これは……？","ENG":"Th-this is...","TWN":"這，這是……？"},"stage":{"bg":"MAINSTREAM_6100016","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWAN_SWANSONG_NPC_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L48_1","type":"dialog","speaker":"SWAN_SWANSONG_NPC_NULL","text":{"KOREA":"으윽, 시체잖아……? 목 위가 잘려 나가서 없어……!","JPN":"うっ……死体……？　首の上が切り落とされた……","ENG":"Ugh, it's a corpse...? And the head is gone...!","TWN":"是屍體……？頭被砍掉了……！"},"stage":{"bg":"MAINSTREAM_6100016","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWAN_SWANSONG_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L49_1","type":"dialog","speaker":"SWAN_SWANSONG_NPC_NULL","text":{"KOREA":"자, 잠깐? 이 피로 쓴 메시지는……?","JPN":"ちょ、ちょっと……？　血で書かれたこのメッセージは……？","ENG":"W-what? There's a message written in blood...","TWN":"等，等一下？這個用血寫的塗鴉是……？"},"stage":{"bg":"MAINSTREAM_6100016","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWAN_SWANSONG_NPC_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L50_1","type":"dialog","speaker":"SWAN_SWANSONG_NPC_NULL","text":{"KOREA":"<color=#ffd34c>네 번째 시련을 지나라, 그녀는 불꽃에 달궈진 철이 될지니.</color>","JPN":"<color=#ffd34c>四つ目の試練を越えろ、彼女は炎で煉られた鉄になるだろう。</color>","ENG":"<color=#ffd34c>Pass the fourth ordeal, and she will become iron heated in flame.</color>","TWN":"<color=#ffd34c>經歷第四之裁判，她將會是淬火的鐵。</color>"},"stage":{"bg":"MAINSTREAM_6100016","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWAN_SWANSONG_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L1_1","type":"dialog","speaker":"SWAN_SWANSONG_NPC_NULL","text":{"KOREA":"네 번째라고……?","JPN":"四つ目ですって……？","ENG":"Fourth...?","TWN":"第四之裁判……？"},"stage":{"bg":"MAINSTREAM_6100016","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWAN_SWANSONG_NPC_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L2_1","type":"dialog","speaker":"SWAN_SWANSONG_NPC_NULL","text":{"KOREA":"그렇다면 이 시체가…… 설마, 심야의 살인마의……?","JPN":"ということは、この死体が……まさか、深夜の殺人鬼の……？","ENG":"Then that means that this corpse is... the Midnight Killer's doing...?","TWN":"難道這具屍體是……午夜殺人魔幹的……？"},"stage":{"bg":"MAINSTREAM_6100016","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWAN_SWANSONG_NPC_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"SWAN_SWANSONG_NPC_NULL","text":{"KOREA":"바, 발소리……?","JPN":"あ、足音が……","ENG":"F-footsteps...!","TWN":"有人來了……？"},"stage":{"bg":"BACKSTREET","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWAN_SWANSONG_NPC_NULL","face":"UNIT_SURPRISE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L7_1","type":"dialog","speaker":"SWAN_SWANSONG_NPC_NULL","text":{"KOREA":"이러다 들키겠어! 빨리 숨지 않으면……!","JPN":"このままじゃ見つかってしまう！　早く隠れないと……！","ENG":"I'm going to get caught if I don't hide...!","TWN":"這樣下去會被發現的！快躲起來……！"},"stage":{"bg":"BACKSTREET","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWAN_SWANSONG_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L10_1","type":"narration","speaker":null,"text":{"KOREA":"조부가 남긴 <color=#ffd34c>회중 시계</color>가 내게 부여한 능력은 <color=#ffd34c>완전 기억</color>.","JPN":"祖父が残した<color=#ffd34c>懐中時計</color>が私に与えた能力は<color=#ffd34c>完全記憶</color>。","ENG":"The <color=#ffd34c>pocket watch</color> that my grandparents left me granted me with my ability of <color=#ffd34c>perfect memory</color>.","TWN":"祖父留下的<color=#ffd34c>懷錶</color>賦予了我<color=#ffd34c>完全記憶</color>的能力。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L11_1","type":"narration","speaker":null,"text":{"KOREA":"나는 지나간 모든 것을 기억한다.","JPN":"私は経験したすべてを記憶する。","ENG":"I remember everything.","TWN":"我能記得過去發生的一切事情。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L14_1","type":"narration","speaker":null,"text":{"KOREA":"덕분에 어떠한 대본도, 노래도, 연기자의 표정도 한 번만 보면 완벽하게 따라할 수 있었다.","JPN":"おかげでどんな台本も、歌も、役者の表情も、一度見ただけで完璧に真似ることができる。","ENG":"Thanks to that, I was able to perfectly recite any script or song, and even imitate an actor's expression just by seeing it once.","TWN":"因此，無論是劇本、歌曲，還是演員的表情，只要看一遍我就能完美模仿。"},"stage":{"bg":"GRONIA_HALL","bgm":"CUTSCENE_TALK_02","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}},{"id":"L15_1","type":"narration","speaker":null,"text":{"KOREA":"배우로서, 그것은 틀림없는 더할 나위 없는 축복.","JPN":"役者としてそれはこれ以上ないほどの祝福だ。","ENG":"As an actress, it was without a doubt a blessing.","TWN":"作為演員，這無疑是無上的祝福。"},"stage":{"bg":"GRONIA_HALL","bgm":"CUTSCENE_TALK_02","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}},{"id":"L21_1","type":"narration","speaker":null,"text":{"KOREA":"그렇기에 직감했다.","JPN":"だから直感でわかった。","ENG":"That is why I instinctively knew.","TWN":"直覺在提示著我。"},"stage":{"bg":"SKY_NIGHT","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L22_1","type":"narration","speaker":null,"text":{"KOREA":"어스름한 달빛과, 불쾌하게 피부에 스며드는 밤안개, 비릿한 피 냄새.","JPN":"薄暗い月明かり、肌に染み込む不快な夜の霧、生臭い血の匂い。","ENG":"The dusky moonlight, the night fog seeping into my skin repulsively, the stench of metallic blood.","TWN":"昏暗的月光，令人不快地想要滲入皮膚的濃霧，腥臭的血味。"},"stage":{"bg":"SKY_NIGHT","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L23_1","type":"narration","speaker":null,"text":{"KOREA":"그리고…….","JPN":"そして……","ENG":"Also...","TWN":"還有……"},"stage":{"bg":"SKY_NIGHT","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L27_1","type":"dialog","speaker":"MORS_SHADOW_ARMOR_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"BACKSTREET3","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MORS_SHADOW_ARMOR_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_COMBAT_ALL_FOOT_STEP_LANDING_BIG_02"},{"id":"L28_1","type":"dialog","speaker":"MORS_SHADOW_ARMOR_NULL","text":{"KOREA":"역병의 악취가 짙어지는구나. 이 땅에도 곧 종말이 도래하리니.","JPN":"疫病の悪臭が濃くなっている。もうじきこの地にも終末が到来するであろう。","ENG":"The foul stench of the plague grows ever thicker. Will this realm reach the apocalypse as well?","TWN":"瘟疫的惡臭越來越濃了。這片土地的末日即將來臨。"},"stage":{"bg":"BACKSTREET3","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MORS_SHADOW_ARMOR_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L30_1","type":"dialog","speaker":"SWAN_SWANSONG_NPC_NULL","text":{"KOREA":"저, 저건……?","JPN":"あ、あれは……","ENG":"Th-that's...?","TWN":"那，那是……？"},"stage":{"bg":"BACKSTREET3","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MORS_SHADOW_ARMOR_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L31_1","type":"narration","speaker":null,"text":{"KOREA":"칠흑보다 어두운 갑주와 서슬퍼런 날붙이를 든 이형의 <color=#ffd34c>존재</color>.","JPN":"漆黒より暗い鎧に、冷たく光る刃物を持つ異形の<color=#ffd34c>存在</color>。","ENG":"The strange <color=#ffd34c>being</color> with pitch-black armor and a pale blade.","TWN":"身披比漆黑更深的鎧甲，手持鋒利武器的異形<color=#ffd34c>存在</color>。"},"stage":{"bg":"BACKSTREET3","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MORS_SHADOW_ARMOR_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L32_1","type":"narration","speaker":null,"text":{"KOREA":"런던 풍경과는 동떨어진 그것과 마주하게 되면, 누구라도 깨닫게 되리라.","JPN":"ロンドンの景色とはまったく馴染まないあれを目にすれば、誰でも一瞬で気づくだろう。","ENG":"Anyone who encounters that of which is far removed from London's scenery will realize.","TWN":"當面對與倫敦風景格格不入的東西時，任何人都會意識到。"},"stage":{"bg":"BACKSTREET3","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MORS_SHADOW_ARMOR_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L33_1","type":"narration","speaker":null,"text":{"KOREA":"저건, 틀림없이 이 세상의 존재가 아니라고.","JPN":"あれはこの世の存在ではない。","ENG":"That being is not of this world.","TWN":"那絕對不是這個世界的存在。"},"stage":{"bg":"BACKSTREET3","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MORS_SHADOW_ARMOR_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L34_1","type":"narration","speaker":null,"text":{"KOREA":"마물에 가까운 존재라고.","JPN":"魔物に近い存在なのだと。","ENG":"And is something that closely resembles a monster.","TWN":"那更像是怪物的存在。"},"stage":{"bg":"BACKSTREET3","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MORS_SHADOW_ARMOR_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L35_1","type":"dialog","speaker":"MORS_SHADOW_ARMOR_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"BACKSTREET3","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MORS_SHADOW_ARMOR_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L36_1","type":"dialog","speaker":"MORS_SHADOW_ARMOR_NULL","text":{"KOREA":"하지만 나는 좌시하지 않으리라.","JPN":"だが我は座視せぬ。","ENG":"But I do not idly sit by.","TWN":"但我不會坐視不管。"},"stage":{"bg":"BACKSTREET3","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MORS_SHADOW_ARMOR_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L37_1","type":"dialog","speaker":"MORS_SHADOW_ARMOR_NULL","text":{"KOREA":"속죄를 위해서라도, 반드시 죄인을 처단하겠다.","JPN":"贖罪のため、必ず罪人を処断しよう。","ENG":"I will smite the sinner as my atonement.","TWN":"即使是為了贖罪，也必須處決罪人。"},"stage":{"bg":"BACKSTREET3","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MORS_SHADOW_ARMOR_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L38_1","type":"narration","speaker":null,"text":{"KOREA":"어스름한 달빛과 불쾌하게 피부에 스며드는 밤안개, 비릿한 피 냄새.","JPN":"薄暗い月明かり、肌に染み込む不快な夜の霧、生臭い血の匂い。","ENG":"The dusky moonlight, the night fog seeping into my skin repulsively, the stench of metallic blood.","TWN":"昏暗的月光，令人不快地想要滲入皮膚的濃霧，腥臭的血味。"},"stage":{"bg":"BACKSTREET3","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MORS_SHADOW_ARMOR_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L39_1","type":"narration","speaker":null,"text":{"KOREA":"목이 잘린 시체와 피로 쓴 낙서.\\n 그리고 피 눈물 흘리는 듯한 붉은 안광의 검은 갑주…….","JPN":"首の切り落とされた死体と血で書いた落書き。\\n血の涙を流しているような、赤い眼光を放つ黒い鎧の何者か……","ENG":"The writing in blood and a headless corpse.\\nAnd the black armor with glowing red eyes as if tearing blood…","TWN":"被斬首的屍體和用血寫成的塗鴉。\\n 還有閃爍著血淚般紅光的黑色鎧甲……"},"stage":{"bg":"BACKSTREET3","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MORS_SHADOW_ARMOR_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L40_1","type":"narration","speaker":null,"text":{"KOREA":"나는 지나간 모든 것을 기억한다.","JPN":"私は経験したすべてを記憶する。","ENG":"I remember everything.","TWN":"我能記得過去發生的一切事情。"},"stage":{"bg":"BACKSTREET3","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MORS_SHADOW_ARMOR_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L41_1","type":"narration","speaker":null,"text":{"KOREA":"내 의지와는 관계없이.\\n내 눈은 탐욕스럽게 정보를 탐하여 뇌리에 광기의 풍경을 새긴다.","JPN":"私の意思とは関係なく。\\n私の目は情報を貪り、狂気に濡れた風景を脳裏に焼き付ける。","ENG":"Regardless of my will.\\nMy eyes greedily seek information and engrave the scenes of madness into my mind.","TWN":"不由自主地，\\n眼睛貪婪地搜尋著資訊，將這片瘋狂的景象銘刻在我的腦海中。"},"stage":{"bg":"BACKSTREET3","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MORS_SHADOW_ARMOR_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L42_1","type":"narration","speaker":null,"text":{"KOREA":"인간으로서, 그것은 틀림없이 마음을 깎아내리는 저주.","JPN":"人間として、それは心を削られるような呪いだった。","ENG":"As a human, this must be a curse that carves away one's soul.","TWN":"作為人類，這無疑是一種折磨心靈的詛咒。"},"stage":{"bg":"BACKSTREET3","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MORS_SHADOW_ARMOR_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L46_1","type":"dialog","speaker":"MORS_SHADOW_ARMOR_NULL","text":{"KOREA":"……누구인가.","JPN":"……何者だ。","ENG":"...Who is it?","TWN":"……是誰。"},"stage":{"bg":"BACKSTREET3","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MORS_SHADOW_ARMOR_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L47_1","type":"dialog","speaker":"SWAN_SWANSONG_NPC_NULL","text":{"KOREA":"큿……!?","JPN":"くっ……！？","ENG":"Kgh...?!","TWN":"咳……！?"},"stage":{"bg":"BACKSTREET3","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWAN_SWANSONG_NPC_NULL","face":"UNIT_HATE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L1_1","type":"dialog","speaker":"MARYJANE_SWANSONG_NPC_NULL","text":{"KOREA":"이쪽이야!! 스완……!!","JPN":"こっちだよ、スワン……！！","ENG":"Over here!! Swan...!!","TWN":"這邊！！史旺……！！"},"stage":{"bg":"BACKSTREET3","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MARYJANE_SWANSONG_NPC_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SWAN_SWANSONG_NPC_NULL","face":"UNIT_IDLE"}}}},{"id":"L2_1","type":"dialog","speaker":"SWAN_SWANSONG_NPC_NULL","text":{"KOREA":"메리 제인……?","JPN":"メリー・ジェーン……？","ENG":"Mary Jane...?","TWN":"瑪麗·珍……？"},"stage":{"bg":"BACKSTREET3","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MARYJANE_SWANSONG_NPC_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SWAN_SWANSONG_NPC_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L3_1","type":"dialog","speaker":"MARYJANE_SWANSONG_NPC_NULL","text":{"KOREA":"당장 일어서! 살해당한다고!!","JPN":"早く立って！　殺される！！","ENG":"Get up! Or you're going to die!!","TWN":"馬上站起來！會被殺掉的！！"},"stage":{"bg":"BACKSTREET3","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MARYJANE_SWANSONG_NPC_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SWAN_SWANSONG_NPC_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L4_1","type":"dialog","speaker":"SWAN_SWANSONG_NPC_NULL","text":{"KOREA":"어, 어어……?","JPN":"え、ええっ……？","ENG":"H-huh...?","TWN":"啊？啊啊……？"},"stage":{"bg":"BACKSTREET3","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MARYJANE_SWANSONG_NPC_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SWAN_SWANSONG_NPC_NULL","face":"UNIT_IDLE"}}}},{"id":"L7_1","type":"dialog","speaker":"MORS_SHADOW_ARMOR_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"BACKSTREET3","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MARYJANE_SWANSONG_NPC_NULL","face":"UNIT_IDLE"},"C":{"char_id":"MORS_SHADOW_ARMOR_NULL","face":"UNIT_IDLE"},"R":{"char_id":"SWAN_SWANSONG_NPC_NULL","face":"UNIT_IDLE"}}}}]`);export{e as default};